const today = new Date().toISOString().split('T')[0];

return $input.all().map(item => {
  const raw = item.json;
  const priceClean = (raw.price || '')
    .replace(/[^0-9.]/g, '')
    .trim();

  return {
    json: {
      title:       (raw.title || '').trim(),
      price:       raw.price  || '',
      priceNum:    parseFloat(priceClean) || 0,
      scrapedDate: today
    }
  };
});

const all = $('7. Code — Add Date and Clean Price').all();
const today = all[0]?.json.scrapedDate || new Date().toISOString().split('T')[0];

const prices = all.map(i => i.json.priceNum).filter(p => p > 0);
const maxPrice = prices.length > 0 ? Math.max(...prices) : 0;
const minPrice = prices.length > 0 ? Math.min(...prices) : 0;
const avgPrice = prices.length > 0 ? (prices.reduce((a, b) => a + b, 0) / prices.length).toFixed(2) : 0;
const total    = all.length;

const top10 = all.slice(0, 10)
  .map(i => i.json.title + ' — ' + i.json.price)
  .join('\n');

const bottom5 = all.slice(-5)
  .map(i => i.json.title + ' — ' + i.json.price)
  .join('\n');

const analysisContext = [
  'SCRAPE DATE: ' + today,
  'WEBSITE: books.toscrape.com',
  'TOTAL PRODUCTS FOUND: ' + total,
  'HIGHEST PRICE: ' + maxPrice,
  'LOWEST PRICE: ' + minPrice,
  'AVERAGE PRICE: ' + avgPrice,
  '',
  'TOP 10 MOST EXPENSIVE:',
  top10,
  '',
  'BOTTOM 5 CHEAPEST:',
  bottom5
].join('\n');

return [{ json: { analysisContext, total, maxPrice, minPrice, avgPrice, today } }];

const csvBinary = $('11. Convert to CSV File').first();
const aiOutput  = $('10. AI Agent — Price Analysis').first().json.output || 'AI analysis not available.';
const stats     = $('9. Code — Compile for AI and Stats').first().json;

return [{
  json: {
    aiInsight: aiOutput,
    total:     stats.total,
    maxPrice:  stats.maxPrice,
    minPrice:  stats.minPrice,
    avgPrice:  stats.avgPrice,
    today:     stats.today
  },
  binary: csvBinary.binary
}];
